import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"798艺术区","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/798-art-zone.md","filePath":"landmarks/798-art-zone.md","lastUpdated":1784773307000}'),n={name:"landmarks/798-art-zone.md"};function d(s,t,o,i,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="_798艺术区" tabindex="-1">798艺术区 <a class="header-anchor" href="#_798艺术区" aria-label="Permalink to &quot;798艺术区&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-AWr2a2EK_A8?w=1200" alt="798艺术区"></p><blockquote><p>&quot;老厂房里的艺术梦想，工业与时尚的完美碰撞。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>798艺术区位于北京市朝阳区酒仙桥街道，由原北京798厂等电子工业老厂区改造而成，是中国当代艺术的重要展示平台。这里汇聚了画廊、艺术家工作室、设计公司、时尚店铺等，是北京最具国际影响力的艺术区。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">10:00-18:00（画廊），部分店铺延长至22:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费（部分展览收费）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁14号线望京南站/地铁10号线亮马桥站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区酒仙桥路2号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="工业时期-1950-1990年代" tabindex="-1">工业时期（1950-1990年代） <a class="header-anchor" href="#工业时期-1950-1990年代" aria-label="Permalink to &quot;工业时期（1950-1990年代）&quot;">​</a></h3><p>798艺术区的前身是北京798厂等电子工业厂区，建于20世纪50年代。这里曾是中国电子工业的重要基地，生产过大量电子元器件。</p><h4 id="建筑风格" tabindex="-1">建筑风格 <a class="header-anchor" href="#建筑风格" aria-label="Permalink to &quot;建筑风格&quot;">​</a></h4><p>厂区的建筑多为包豪斯风格，由德国专家设计，是中国最早采用包豪斯风格的建筑群之一。</p><h3 id="艺术转型-2000年代" tabindex="-1">艺术转型（2000年代） <a class="header-anchor" href="#艺术转型-2000年代" aria-label="Permalink to &quot;艺术转型（2000年代）&quot;">​</a></h3><p>2002年，一批艺术家开始在这里租用废弃的厂房作为工作室。2006年，798艺术区正式命名为&quot;北京798艺术区&quot;。</p><h4 id="发展历程" tabindex="-1">发展历程 <a class="header-anchor" href="#发展历程" aria-label="Permalink to &quot;发展历程&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">事件</th></tr></thead><tbody><tr><td style="text-align:left;">2002年</td><td style="text-align:left;">第一批艺术家入驻</td></tr><tr><td style="text-align:left;">2004年</td><td style="text-align:left;">画廊和艺术机构大量进驻</td></tr><tr><td style="text-align:left;">2006年</td><td style="text-align:left;">正式命名&quot;北京798艺术区&quot;</td></tr><tr><td style="text-align:left;">2007年</td><td style="text-align:left;">举办首届798艺术节</td></tr><tr><td style="text-align:left;">2010年</td><td style="text-align:left;">成为北京文化创意产业的重要基地</td></tr></tbody></table><h2 id="主要区域" tabindex="-1">主要区域 <a class="header-anchor" href="#主要区域" aria-label="Permalink to &quot;主要区域&quot;">​</a></h2><h3 id="画廊区" tabindex="-1">画廊区 <a class="header-anchor" href="#画廊区" aria-label="Permalink to &quot;画廊区&quot;">​</a></h3><p>798艺术区内有众多国内外知名画廊，展示着各种当代艺术作品。</p><h4 id="知名画廊" tabindex="-1">知名画廊 <a class="header-anchor" href="#知名画廊" aria-label="Permalink to &quot;知名画廊&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">画廊</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>佩斯画廊</strong></td><td style="text-align:left;">国际知名画廊，展示当代艺术</td></tr><tr><td style="text-align:left;"><strong>长征空间</strong></td><td style="text-align:left;">中国当代艺术重要平台</td></tr><tr><td style="text-align:left;"><strong>唐人当代艺术中心</strong></td><td style="text-align:left;">展示亚洲当代艺术</td></tr><tr><td style="text-align:left;"><strong>站台中国</strong></td><td style="text-align:left;">关注中国当代艺术</td></tr></tbody></table><h3 id="艺术家工作室" tabindex="-1">艺术家工作室 <a class="header-anchor" href="#艺术家工作室" aria-label="Permalink to &quot;艺术家工作室&quot;">​</a></h3><p>798艺术区内有大量艺术家工作室，游客可以近距离接触艺术家的创作过程。</p><h4 id="工作室特色" tabindex="-1">工作室特色 <a class="header-anchor" href="#工作室特色" aria-label="Permalink to &quot;工作室特色&quot;">​</a></h4><ul><li><strong>雕塑工作室</strong>：可以观看雕塑创作过程</li><li><strong>绘画工作室</strong>：可以观看油画、国画创作</li><li><strong>装置艺术工作室</strong>：可以了解装置艺术的创作理念</li></ul><h3 id="创意市集" tabindex="-1">创意市集 <a class="header-anchor" href="#创意市集" aria-label="Permalink to &quot;创意市集&quot;">​</a></h3><p>798艺术区内经常举办创意市集，出售各种原创设计产品。</p><h4 id="市集特色" tabindex="-1">市集特色 <a class="header-anchor" href="#市集特色" aria-label="Permalink to &quot;市集特色&quot;">​</a></h4><ul><li><strong>原创设计</strong>：服装、饰品、家居用品等</li><li><strong>手工艺品</strong>：陶艺、木作、皮具等</li><li><strong>艺术衍生品</strong>：画册、明信片、文创产品等</li></ul><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">特色</th><th style="text-align:left;">看点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>798创意广场</strong></td><td style="text-align:left;">艺术区中心</td><td style="text-align:left;">各种艺术装置</td></tr><tr><td style="text-align:left;"><strong>火车头广场</strong></td><td style="text-align:left;">工业遗存</td><td style="text-align:left;">老式火车头</td></tr><tr><td style="text-align:left;"><strong>包豪斯广场</strong></td><td style="text-align:left;">建筑艺术</td><td style="text-align:left;">包豪斯风格建筑</td></tr><tr><td style="text-align:left;"><strong>涂鸦墙</strong></td><td style="text-align:left;">街头艺术</td><td style="text-align:left;">各种涂鸦作品</td></tr><tr><td style="text-align:left;"><strong>艺术书店</strong></td><td style="text-align:left;">文化空间</td><td style="text-align:left;">艺术书籍、画册</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约3小时）</strong>：</p><p>798创意广场 → 画廊区 → 艺术家工作室 → 创意市集 → 火车头广场 → 包豪斯广场 → 涂鸦墙</p><p><strong>深度路线（约一天）</strong>：</p><p>上午：画廊区 → 艺术家工作室 下午：创意市集 → 包豪斯广场 → 涂鸦墙 → 艺术书店 晚上：798内餐厅用餐，感受艺术区夜生活</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：周末人较多，建议工作日前往</li><li><strong>展览信息</strong>：关注798官网，了解最新展览信息</li><li><strong>拍照打卡</strong>：涂鸦墙、火车头、创意广场都是绝佳拍照点</li><li><strong>购物建议</strong>：创意市集上的商品价格可以议价</li><li><strong>餐饮推荐</strong>：798内有很多特色餐厅和咖啡馆</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">14号线望京南站，步行约15分钟</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">401、402、405、418、909路大山子路口南站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;798艺术区&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">望京SOHO</td><td style="text-align:center;">约3公里</td><td style="text-align:left;">现代建筑地标</td></tr><tr><td style="text-align:left;">颐堤港</td><td style="text-align:center;">约2公里</td><td style="text-align:left;">购物中心</td></tr><tr><td style="text-align:left;">将府公园</td><td style="text-align:center;">约2公里</td><td style="text-align:left;">城市公园</td></tr><tr><td style="text-align:left;">中央美术学院美术馆</td><td style="text-align:center;">约3公里</td><td style="text-align:left;">艺术展览</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>798艺术区是中国当代艺术的发源地之一，也是中国文化创意产业的标杆。这里不仅展示了当代艺术的魅力，更体现了中国城市更新的成功案例。</p><p>&quot;工业遗存+当代艺术&quot;的模式，让老厂房焕发了新的生命力，也为城市发展提供了新的思路。</p><hr><p><strong>📍 地址</strong>：北京市朝阳区酒仙桥路2号 <strong>🚇 地铁</strong>：14号线望京南站，步行约15分钟 ** 电话**：010-59789898 <strong>🌐 官网</strong>：<a href="http://www.798artdistrict.com.cn" target="_blank" rel="noreferrer">www.798artdistrict.com.cn</a></p><p><strong>💡 Tips</strong>：798艺术区的展览经常更新，建议关注官网了解最新展览信息。</p>',49)])])}const y=e(n,[["render",d]]);export{f as __pageData,y as default};
